from django.db.models import QuerySet
from typing import Optional

# Good: Full type hints with django-stubs types
def get_active_orders(user: User) -> QuerySet[Order]:
    """Fetch all active orders for a user."""
    return Order.objects.filter(
        user=user,
        status__in=["pending", "processing"]
    )

# Good: Optional return type
def get_user_or_none(user_id: int) -> Optional[User]:
    """Get user or return None if not found."""
    return User.objects.filter(pk=user_id).first()

# Good: Service function with keyword-only args
def create_order(
    *,
    user: User,
    items: list[dict],
    shipping_address_id: int,
) -> Order:
    """Service functions take keyword-only args."""
